WITH merged_orders AS (
    SELECT MIN(id) AS id, external_reference, SUM(amount) AS total_amount
    FROM orders
    GROUP BY external_reference
)
DELETE FROM orders
WHERE id NOT IN (SELECT id FROM merged_orders);

INSERT INTO orders (external_reference, total_amount)
SELECT external_reference, total_amount FROM merged_orders;

WITH merged_orders AS (
    SELECT external_reference_number, 
           SUM(order_amount) AS total_order_amount,
           COUNT(*) AS order_count
    FROM orders
    GROUP BY external_reference_number
)
DELETE FROM orders
WHERE external_reference_number IN (
    SELECT external_reference_number FROM merged_orders WHERE order_count > 1
);
INSERT INTO orders (external_reference_number, order_amount)
SELECT external_reference_number, total_order_amount FROM merged_orders;
